using System.Text.Json;
using TradingBot.Api;
using TradingBot.Options;

namespace TradingBot.Services;

public sealed record EdgeTransitionItem(string TransitionId,string WatchlistId,string Strategy,string MarketIdOrGroupKey,string Title,decimal FirstObservedEdge,decimal? PreviousEdge,decimal CurrentEdge,decimal BestObservedEdge,decimal WorstObservedEdge,decimal? EdgeDeltaFromPrevious,decimal EdgeDeltaFromFirst,int Observations,int ImprovingStreak,int WorseningStreak,int StableStreak,bool CrossedNearBreakEven,bool CrossedAlertThreshold,bool CrossedPositiveThreshold,DateTime? FirstCrossedNearBreakEvenUtc,DateTime? FirstCrossedAlertUtc,DateTime? FirstCrossedPositiveUtc,DateTime LastTransitionUtc,string TransitionState,string TransitionReason,bool ValidPriced,bool ExecutionReady,bool PaperEligibleByStrategy,bool PaperDiagnosticsLimitedEligible,bool WouldOpenIfGateAllowed,bool ActualPaperOpened,string RecommendedAction,int ConsecutiveMissing);
public sealed record EdgeTransitionSnapshot(bool Enabled,int Tracked,int New,int Improving,int Worsening,int StableNearBreakEven,int AlertCandidates,int PositiveCandidates,int Invalidated,int Stale,string BestStrategy,decimal? BestCurrentEdge,decimal? BestDeltaFromFirst,decimal? BestDeltaFromPrevious,string LastAlertReason,bool Consistent,IReadOnlyList<EdgeTransitionItem> Items);

public sealed class EdgeTransitionService
{
    private readonly TradingBotOptions _options; private readonly Dictionary<string, EdgeTransitionItem> _items=new(StringComparer.OrdinalIgnoreCase); private readonly object _gate=new(); private string _lastAlertReason="None"; private readonly HashSet<string> _alerted=new(StringComparer.OrdinalIgnoreCase);
    public EdgeTransitionService(TradingBotOptions options)=>_options=options;
    public EdgeTransitionSnapshot Update(FocusUniverseSnapshot? focus, RuntimeHealthSnapshot health, string root)
    {
        var o=_options.EdgeTransition; lock(_gate){ if(!o.Enabled || (o.RequireFocusUniverse && focus?.Enabled!=true)){_items.Clear(); var d=Snapshot(false,health); if(o.ExportEnabled) TryExport(d,health,focus,root); return d;}
        var now=DateTime.UtcNow; var seen=new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        foreach(var f in (focus?.Items ?? Array.Empty<FocusUniverseItem>()).Take(Math.Max(0,o.MaxTrackedTransitions))) { seen.Add(f.WatchlistId); Upsert(f,health,now); }
        foreach(var k in _items.Keys.ToArray().Where(k=>!seen.Contains(k))) MarkMissing(k,now);
        EvictToCap(o.MaxTrackedTransitions); var s=Snapshot(true,health); if(!s.Consistent) Console.WriteLine("[EDGE_TRANSITION_WARNING] Reason=ConsistencyMismatch");
        Console.WriteLine($"[EDGE_TRANSITION_SUMMARY] Enabled={s.Enabled.ToString().ToLowerInvariant()} Tracked={s.Tracked} Improving={s.Improving} Worsening={s.Worsening} StableNearBreakEven={s.StableNearBreakEven} AlertCandidates={s.AlertCandidates} PositiveCandidates={s.PositiveCandidates} BestStrategy={s.BestStrategy} BestCurrentEdge={s.BestCurrentEdge?.ToString("0.####") ?? "N/A"} BestDeltaFromFirst={s.BestDeltaFromFirst?.ToString("0.####") ?? "N/A"} BestDeltaFromPrevious={s.BestDeltaFromPrevious?.ToString("0.####") ?? "N/A"} LastAlertReason={s.LastAlertReason} Consistent={s.Consistent.ToString().ToLowerInvariant()}");
        if(o.ExportEnabled) TryExport(s,health,focus,root); return s; }}
    private void Upsert(FocusUniverseItem f, RuntimeHealthSnapshot h, DateTime now){var o=_options.EdgeTransition; var edge=f.CurrentAfterSafetyEdge; _items.TryGetValue(f.WatchlistId,out var p); var first=p?.FirstObservedEdge ?? edge; var prev=p?.CurrentEdge; decimal? delta=prev.HasValue ? edge-prev.Value : null; var df=edge-first; var obs=(p?.Observations??0)+1; var valid=f.ValidPriced && !IsInvalidReason(f.LastRejectedReason); var improving=delta>=o.MinImprovementDelta; var worsening=delta<=-o.MinImprovementDelta; var stable=delta.HasValue && Math.Abs(delta.Value)<o.MinImprovementDelta; var ist=improving?(p?.ImprovingStreak??0)+1:0; var wst=worsening?(p?.WorseningStreak??0)+1:0; var sst=stable?(p?.StableStreak??0)+1:0; var enough=obs>=o.MinObservations; var near=(p?.CrossedNearBreakEven??false)||(valid&&enough&&edge>=o.NearBreakEvenThreshold); var alert=(p?.CrossedAlertThreshold??false)||(valid&&enough&&edge>=o.AlertThreshold); var pos=(p?.CrossedPositiveThreshold??false)||(valid&&enough&&edge>o.PositiveThreshold); string state,reason; if(!valid){state="Invalidated";reason=f.LastRejectedReason;} else if(enough&&edge>o.PositiveThreshold){state="PositiveCandidate";reason="CrossedPositiveThreshold";} else if(enough&&edge>=o.AlertThreshold){state="AlertCandidate";reason="CrossedAlertThreshold";} else if(obs>=o.StableWindowObservations && edge>=o.NearBreakEvenThreshold){state="StableNearBreakEven";reason="StableNearBreakEven";} else if(improving){state="Improving";reason="ImprovingDelta";} else if(worsening){state="Worsening";reason="WorseningDelta";} else {state=p is null?"New":"StableNearBreakEven";reason=p is null?"NewObservation":"Stable";} var action=state switch{"Invalidated"=>"IgnoreInvalidated","Stale"=>"DropStale","PositiveCandidate"=>"AlertPositiveShadowOnly","AlertCandidate"=>"AlertNearBreakEven","StableNearBreakEven"=>"KeepWatching",_=>"NoAction"}; var paperEligible=f.Strategy.Equals("SingleMarketBuyBoth",StringComparison.OrdinalIgnoreCase); var would=paperEligible&&f.ExecutionReady&&h.PaperDiagnosticsLimitedEligible; var item=new EdgeTransitionItem(p?.TransitionId??$"edge-transition:{Guid.NewGuid():N}",f.WatchlistId,f.Strategy,f.MarketIdOrGroupKey,f.Title,first,prev,edge,Math.Max(p?.BestObservedEdge??edge,edge),Math.Min(p?.WorstObservedEdge??edge,edge),delta,df,obs,ist,wst,sst,near,alert,pos,(p?.FirstCrossedNearBreakEvenUtc)??(near ? now : (DateTime?)null),(p?.FirstCrossedAlertUtc)??(alert ? now : (DateTime?)null),(p?.FirstCrossedPositiveUtc)??(pos ? now : (DateTime?)null),now,state,reason,valid,f.ExecutionReady,paperEligible,h.PaperDiagnosticsLimitedEligible,would,f.PaperOpened,action,0); _items[f.WatchlistId]=item; if((state=="AlertCandidate"||state=="PositiveCandidate") && _alerted.Add($"{item.WatchlistId}|{state}")){_lastAlertReason=reason; Console.WriteLine($"[EDGE_TRANSITION_ALERT] State={state} Strategy={item.Strategy} MarketOrGroup={item.MarketIdOrGroupKey} Title={San(item.Title)} CurrentEdge={item.CurrentEdge:0.####} DeltaFromFirst={item.EdgeDeltaFromFirst:0.####} DeltaFromPrevious={item.EdgeDeltaFromPrevious?.ToString("0.####")??"N/A"} Observations={item.Observations} PaperDiagnosticsLimitedEligible={item.PaperDiagnosticsLimitedEligible.ToString().ToLowerInvariant()} ExecutionReady={item.ExecutionReady.ToString().ToLowerInvariant()} ActualPaperOpened={item.ActualPaperOpened.ToString().ToLowerInvariant()} Reason={reason}");}}
    private void MarkMissing(string k,DateTime now){var p=_items[k]; var miss=p.ConsecutiveMissing+1; if(miss>=3)_items[k]=p with{TransitionState="Stale",TransitionReason="MissingFromFocusUniverse",ConsecutiveMissing=miss,LastTransitionUtc=now,RecommendedAction="DropStale"}; else _items[k]=p with{ConsecutiveMissing=miss};}
    private void EvictToCap(int cap){foreach(var k in _items.Values.OrderBy(x=>x.TransitionState=="Stale"?0:x.TransitionState=="Invalidated"?1:2).ThenBy(x=>x.CurrentEdge).Take(Math.Max(0,_items.Count-Math.Max(0,cap))).Select(x=>x.WatchlistId).ToArray())_items.Remove(k);}    
    private EdgeTransitionSnapshot Snapshot(bool enabled,RuntimeHealthSnapshot h){var a=_items.Values.OrderByDescending(x=>x.CurrentEdge).ToArray(); var best=a.FirstOrDefault(x=>x.ValidPriced); var totalPositive=h.StrategyCounters.Values.Sum(x=>x.PositiveEdges); var pos=a.Count(x=>x.TransitionState=="PositiveCandidate"&&x.ValidPriced); var paper=a.Count(x=>x.ActualPaperOpened); var consistent=pos==0||totalPositive>0; consistent&=paper<=h.PaperExecutionsCount; return new(enabled,a.Length,a.Count(x=>x.TransitionState=="New"),a.Count(x=>x.TransitionState=="Improving"),a.Count(x=>x.TransitionState=="Worsening"),a.Count(x=>x.TransitionState=="StableNearBreakEven"),a.Count(x=>x.TransitionState=="AlertCandidate"),pos,a.Count(x=>x.TransitionState=="Invalidated"),a.Count(x=>x.TransitionState=="Stale"),best?.Strategy??"N/A",best?.CurrentEdge,best?.EdgeDeltaFromFirst,best?.EdgeDeltaFromPrevious,_lastAlertReason,consistent,a);}
    private static bool IsInvalidReason(string? r){var s=r??""; string[] b=["MissingYesAsk","MissingNoAsk","SuspiciousYesNoAskSum","TokenOutcomeMappingUnverified","ReviewOnly","DataQualityRejected","MissingPricing"]; return b.Any(x=>s.Contains(x,StringComparison.OrdinalIgnoreCase));}
    private static string San(string s)=>s.Replace('\n',' ').Replace('\r',' ').Replace('=','-');
    private void TryExport(EdgeTransitionSnapshot s,RuntimeHealthSnapshot h,FocusUniverseSnapshot? f,string root){try{var path=Path.Combine(root,"exports/edge-transition-watchlist-latest.json");Directory.CreateDirectory(Path.GetDirectoryName(path)!);var payload=new{generatedAtUtc=DateTime.UtcNow,h.ProcessRunId,h.Uptime,enabled=s.Enabled,diagnosticsOnly=_options.EdgeTransition.DiagnosticsOnly,focusUniverseEnabled=f?.Enabled??false,h.PaperDiagnosticsLimitedEligible,h.OrderbookStableNow,h.ReducedUniverseOrderbookStableNow,tracked=s.Tracked,improving=s.Improving,worsening=s.Worsening,stableNearBreakEven=s.StableNearBreakEven,alertCandidates=s.AlertCandidates,positiveCandidates=s.PositiveCandidates,invalidated=s.Invalidated,stale=s.Stale,consistent=s.Consistent,items=s.Items.Take(_options.EdgeTransition.MaxTrackedTransitions).Select((x,i)=>new{rank=i+1,x.TransitionId,x.WatchlistId,x.Strategy,marketIdGroupKey=x.MarketIdOrGroupKey,x.Title,x.TransitionState,x.TransitionReason,x.FirstObservedEdge,x.PreviousEdge,x.CurrentEdge,x.BestObservedEdge,x.EdgeDeltaFromPrevious,x.EdgeDeltaFromFirst,x.Observations,x.ImprovingStreak,x.WorseningStreak,x.StableStreak,x.CrossedNearBreakEven,x.CrossedAlertThreshold,x.CrossedPositiveThreshold,x.ValidPriced,x.ExecutionReady,x.PaperEligibleByStrategy,x.PaperDiagnosticsLimitedEligible,x.WouldOpenIfGateAllowed,x.ActualPaperOpened,x.RecommendedAction})};var json=JsonSerializer.Serialize(payload,new JsonSerializerOptions{WriteIndented=true,PropertyNamingPolicy=JsonNamingPolicy.CamelCase});var tmp=path+".tmp";for(var i=0;i<3;i++){try{File.WriteAllText(tmp,json);File.Move(tmp,path,true);break;}catch(IOException) when(i<2){Thread.Sleep(50);}}}catch(Exception ex){Console.WriteLine($"[EDGE_TRANSITION_EXPORT_WARNING] Error={ex.Message}");}}
}
